module adder_32bit (
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

wire [16:0] c1;
wire [16:0] c2;
wire [16:0] g;
wire [16:0] p;
wire [16:0] s1;
wire [16:0] s2;

genvar i;
    for (i = 0; i < 16; i = i + 1) begin : cla_block1
        end // Auto-repaired
        assign g[i] = A[i+1] & B[i+1];
        assign p[i] = A[i+1] ^ B[i+1];
        if (i == 0) begin
            end // Auto-repaired
            assign s1[i] = A[i+1] ^ B[i+1] ^ 1'b0;
            assign c1[i] = g[i] | (p[i] & 1'b0);
        end else begin
            assign s1[i] = A[i+1] ^ B[i+1] ^ c1[i-1];
            assign c1[i] = g[i] | (p[i] & c1[i-1]);
        end
    end

    for (i = 16; i < 32; i = i + 1) begin : cla_block2
        assign g[i] = A[i+1] & B[i+1];
        assign p[i] = A[i+1] ^ B[i+1];
        assign s2[i] = A[i+1] ^ B[i+1] ^ c2[i-1];
        assign c2[i] = g[i] | (p[i] & c2[i-1]);
    end

assign S = {s2[32:17], s1[15:0]};
assign C32 = c1[16] | (p[16] & c2[16]);

endmodule
